// Internal-secret auth: a poller / monitor workflow calls this endpoint.
// No session token. Auth via shared secret in `X-Internal-Secret` header,
// compared to $env.INTERNAL_BID_PARSER_SECRET. If unset, refuse all
// traffic (fail-closed).
const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const incoming = headers['x-internal-secret'] || headers['X-Internal-Secret'] || '';
const expected = $env.INTERNAL_BID_PARSER_SECRET || '';
if (!expected || incoming !== expected) {
  return { json: { ok: false, status: 401, error: 'Missing or invalid X-Internal-Secret' } };
}

const auctionId = String(body.auction_id || '').trim();
const source    = String(body.source_platform || '').trim().toLowerCase();
const rawInput  = String(body.raw_input || '').trim();
const bidderTrustId = String(body.bidder_trust_id || '').trim() || null;
const sourceCommentId = body.source_comment_id || null;

if (!auctionId) return { json: { ok: false, status: 400, error: 'auction_id required' } };
if (!source)    return { json: { ok: false, status: 400, error: 'source_platform required' } };
if (!rawInput)  return { json: { ok: false, status: 400, error: 'raw_input required (the original comment / message text)' } };
if (!bidderTrustId) return { json: { ok: false, status: 400, error: 'bidder_trust_id required — resolve the bidder before calling this endpoint' } };

const allowedSources = ['tiktok_comment','facebook_comment','instagram_dm','web_form','sms','whatsapp'];
if (allowedSources.indexOf(source) === -1) {
  return { json: { ok: false, status: 400, error: 'invalid source_platform; must be one of: ' + allowedSources.join(', ') } };
}

// Parse amount: tolerate variations like 'BID 50', 'bid $50', '$50', '50',
// 'I bid 50.00', 'BIDDING 100'. Strip non-numeric except '.', take the
// first numeric token. Convert dollars -> cents.
const match = rawInput.replace(/[,]/g, '').match(/(\$\s*)?(\d+(?:\.\d{1,2})?)/);
if (!match) {
  return { json: { ok: false, status: 400, error: 'Could not parse a numeric amount from raw_input: ' + rawInput.slice(0, 100) } };
}
const amountDollars = parseFloat(match[2]);
if (isNaN(amountDollars) || amountDollars <= 0) {
  return { json: { ok: false, status: 400, error: 'Parsed amount is zero or negative: ' + match[2] } };
}
const amountCents = Math.round(amountDollars * 100);

return { json: {
  auction_id:       auctionId,
  source_platform:  source,
  source_comment_id:sourceCommentId,
  raw_input:        rawInput,
  bidder_trust_id:  bidderTrustId,
  amount_cents:     amountCents
} };

// Validate bid against auction state. Decide whether to:
//   reject  → bid not allowed (auction not open, below min, etc.)
//   accept  → insert as active; mark previous high as outbid
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const auctions = allOf('Fetch Auction');
const parsed   = $('Auth + Parse').item.json;
if (auctions.length === 0) {
  return { json: { ok: false, status: 404, error: 'Auction not found: ' + parsed.auction_id } };
}
const a = auctions[0];
if (a.status !== 'open' && a.status !== 'extended') {
  return { json: { ok: false, status: 409, error: 'Auction is not accepting bids (status=' + a.status + ')' } };
}
const currentHigh = a.current_high_bid_cents || 0;
const minIncrement = a.min_increment_cents || 100;
const minimumNext = currentHigh + minIncrement;
if (parsed.amount_cents < minimumNext) {
  return { json: { ok: false, status: 422, error: 'Bid too low. Current high is $' + (currentHigh/100).toFixed(2) + '; minimum next bid is $' + (minimumNext/100).toFixed(2) + '. Your bid was $' + (parsed.amount_cents/100).toFixed(2) + '.' } };
}
// Reserve check — but reserve typically just affects whether the auction
// closes sold or unsold. Bidders can bid below reserve; close logic handles it.
return { json: {
  ok: true,
  bid_body: {
    auction_id:        parsed.auction_id,
    bidder_trust_id:   parsed.bidder_trust_id,
    amount_cents:      parsed.amount_cents,
    source_platform:   parsed.source_platform,
    source_comment_id: parsed.source_comment_id,
    raw_input:         parsed.raw_input,
    status:            'active'
  },
  previous_high_bid_id: a.current_high_bid_id || null,
  auction_patch: {
    current_high_bid_cents: parsed.amount_cents,
    updated_at: new Date().toISOString()
  }
} };

// After Insert Bid: take the new bid's id, also outbid the prior high
// (if any), and PATCH the auction's current_high_bid_id + cents.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const inserted = allOf('Insert Bid');
const v = $('Validate Bid').first().json;
if (inserted.length === 0) return { json: { ok: false, status: 500, error: 'Insert returned no row' } };
const newBid = inserted[0];
const now = new Date().toISOString();
return { json: {
  ok: true,
  bid_id: newBid.id,
  auction_id: newBid.auction_id,
  amount_cents: newBid.amount_cents,
  prev_high_bid_id: v.previous_high_bid_id,
  auction_patch_url: 'https://zqwatouqmqgkmaslydbr.supabase.co/rest/v1/auctions?id=eq.' + newBid.auction_id,
  auction_patch_body: { current_high_bid_cents: newBid.amount_cents, current_high_bid_id: newBid.id, updated_at: now },
  outbid_patch_url:  v.previous_high_bid_id ? ('https://zqwatouqmqgkmaslydbr.supabase.co/rest/v1/auction_bids?id=eq.' + v.previous_high_bid_id) : null,
  outbid_patch_body: { status: 'outbid', outbid_at: now }
} };

const v = $('Build Updates').first().json;
return { json: {
  ok: true,
  bid_id: v.bid_id,
  auction_id: v.auction_id,
  amount_cents: v.amount_cents,
  amount_display: '$' + (v.amount_cents/100).toFixed(2),
  previous_outbid_id: v.prev_high_bid_id || null
} };
